document.addEventListener('DOMContentLoaded',()=>{const getActiveLang=()=>localStorage.getItem('preferred-language')||(navigator.language.startsWith('en')?'en':'it');let currentLang=getActiveLang();const isIt=currentLang==='it';const pad=n=>n<10?'0'+n:n;const getCurrentSeason=()=>{const now=new Date();const dateVal=(now.getMonth()+1)*100+now.getDate();if(dateVal>=321&&dateVal<621)return"spring";if(dateVal>=621&&dateVal<923)return"summer";if(dateVal>=923&&dateVal<1221)return"autumn";return"winter"};let scientificDict={};async function syncScientificDict(){if(typeof window.workerQuery!=='function'){setTimeout(syncScientificDict,100);return}
try{const data=await window.workerQuery('FETCH_SCIENTIFIC_DICT',{path:'./lang/scientific-dict.json'});if(data){scientificDict=data;console.log("%c⚛️ ENGINE %c Dizionario Scientifico sincronizzato (Parallel Mode)","color:#00ff88; background:#112211; font-weight:bold;","color:#8899af;")}}catch(error){console.warn("⚠️ ENGINE: Sincronizzazione dizionario ritardata:",error)}}
syncScientificDict();const formatTip=(title,body,extra="",barPerc=null)=>{let html=`<b>${title.toUpperCase()}</b><br>${body}${extra ? `<br><i>${extra}</i>` : ""}`;if(barPerc!==null){html+=`
            <div class='intensity-container'>
                <div class='intensity-label'>INTENSITY</div>
                <div class='intensity-bar-bg'>
                    <div class='intensity-bar-fill' style='width:${barPerc}%'></div>
                </div>
                <div class='intensity-value'>${barPerc}%</div>
            </div>`}
return html};function initSeasonMonitor(){const countdownEl=document.getElementById('modern-countdown');if(!countdownEl)return;let dataDisplay=document.getElementById('bio-data-display')||document.createElement('div');if(!dataDisplay.id){dataDisplay.id='bio-data-display';countdownEl.innerHTML='';countdownEl.appendChild(dataDisplay)}
const lang={seasons:isIt?{spring:"PRIMAVERA",summer:"ESTATE",autumn:"AUTUNNO",winter:"INVERNO"}:{spring:"SPRING",summer:"SUMMER",autumn:"AUTUMN",winter:"WINTER"},phase:isIt?"FASE CICLO":"CYCLE PHASE"};const updateBioCycle=()=>{const now=new Date(),year=now.getFullYear(),seasonKey=getCurrentSeason();const start=new Date(year,0,1),end=new Date(year+1,0,1);const progress=((now-start)/(end-start))*100,daysLeft=Math.floor((end-now)/86400000);const tooltipMsg=isIt?'Monitoraggio dell\'inclinazione assiale terrestre e impatto metabolico.':'Earth axial tilt monitoring and metabolic impact.';dataDisplay.innerHTML=`
                <div class="bio-season-label" data-bio-tip="${tooltipMsg}">${lang.seasons[seasonKey]} ${lang.phase}</div>
                <div class="bio-progress-data" data-bio-tip="${tooltipMsg}">${progress.toFixed(2)}% <span class="bio-t-minus">| T-MINUS: ${daysLeft}${isIt ? 'G' : 'D'}</span></div>
            `};updateBioCycle();setInterval(updateBioCycle,3600000)}
function initBioClock(){const clockEl=document.getElementById('clock2');if(!clockEl)return;const circadianMap={0:{it:["RIGENERAZIONE GLINFATICA","PULIZIA CEREBRALE","ADENOSINA","BUIO TOTALE"],en:["GLYMPHATIC REGEN","BRAIN CLEARANCE","ADENOSINA","TOTAL DARKNESS"]},3:{it:["RIPARAZIONE TESSUTI","INIZIO PULIZIA","CITOCHINE","SOMATOTROPINA"],en:["TISSUE REPAIR","CLEARANCE START","CYTOKINES","SOMATOTROPIN"]},6:{it:["PICCO DI CORTISOLO","RESET CIRCADIANO","CORTISOLO","LUCE NATURALE"],en:["CORTISOL SPIKE","CIRCADIAN RESET","CORTISOL","NATURAL LIGHT"]},8:{it:["VIGILANZA ELEVATA","NORADRENALINA","DHEA","COLAZIONE PROT."],en:["HIGH VIGILANCE","NOREPINEPHRINE","DHEA","PROTEIN BREAKFAST"]},11:{it:["MASSIMA ALLERTA","PICCO COGNITIVO","GLUTAMMATO","FOCUS ATTIVO"],en:["MAX ALERTNESS","COGNITIVE PEAK","GLUTAMATE","ACTIVE FOCUS"]},12:{it:["STIMOLO ORESSIGENICO","BDNF","GRELINA","PAUSA NUTRIZIONE"],en:["OREXIGENIC STIMULUS","BDNF","GHRELIN","NUTRITION BREAK"]},13:{it:["RISPOSTA LEPTINICA","SAZIETÀ METABOLICA","ADIPONECTINA","PAUSA NUTRIZIONE"],en:["LEPTIN RESPONSE","METABOLIC SATIETY","ADIPONECTIN","NUTRITION BREAK"]},15:{it:["MANTENIMENTO COGNITIVO","STABILITÀ SINAPTICA","ACETILCOLINA","FOCUS ANALITICO"],en:["COGNITIVE MAINT.","SYNAPTIC STABILITY","ACETYLCHOLINE","ANALYTICAL FOCUS"]},17:{it:["PICCO FISICO","ENDORFINE + MIOCHINE","ENDORFINE/MIOCHINE","MOVIMENTO"],en:["PHYSICAL PEAK","ENDORPHINS + MYOKINES","ENDORPHINS/MYOKINES","WORKOUT"]},19:{it:["FINESTRA ANABOLICA","SINTESI PROTEICA","INSULINA","DECOMPRESSIONE"],en:["ANABOLIC WINDOW","PROTEIN SYNTHESIS","INSULIN","DOWNTIME"]},21:{it:["RELAZIONE SOCIALE","OSSITOCINA","ANANDAMIDE","RELAX ATTIVO"],en:["SOCIAL CONNECTION","OXYTOCIN","ANANDAMIDE","ACTIVE RELAX"]},23:{it:["RILASCIO MELATONINA","INIZIO PULIZIA","MELATONINA","NO LUCE BLU"],en:["MELATONIN ONSET","CLEARANCE START","MELATONIN","NO BLUE LIGHT"]}};const getDynamicAdvice=(h,base)=>{const s=getCurrentSeason();const isColdSeason=(s==="winter"||s==="autumn");const isIt=getActiveLang()==='it';if(h>=7&&h<8)return isIt?"VARIAZIONE TERMICA (FREDDO)":"THERMAL VARIATION (COLD)";if(h>=6&&h<9){if(s==="winter")return isIt?"LUCE ART. 10K LUX":"10K LUX ART. LIGHT";if(s==="summer")return isIt?"SOLE DIRETTO 10M":"DIRECT SUN 10M"}
if(h>=10&&h<=12&&isColdSeason){return isIt?"INTEGRA VITAMINA D":"VITAMIN D INTAKE"}
if(h>=13&&h<17&&s==="summer")return isIt?"IDRATAZIONE + SALI":"HYDRATION + SALTS";if(h>=17&&h<19)return isIt?"ALLENAMENTO RESISTENZA":"RESISTANCE TRAINING";if(h>=21&&h<23)return isIt?"FOTOBIOMODULAZIONE (ROSSO)":"PHOTOBIOMODULATION (RED)";if(h>=20&&s==="winter")return isIt?"THERMO-RELAX (CALDO)":"WARM THERMO-RELAX";return base};const updateClock=()=>{const now=new Date();const hour=now.getHours();const mins=now.getMinutes();const isIt=getActiveLang()==='it';const keys=Object.keys(circadianMap).map(Number);const currentKey=[...keys].reverse().find(k=>hour>=k)||0;const currentIndex=keys.indexOf(currentKey);const nextKey=keys[currentIndex+1]||24;const blockDuration=nextKey-currentKey;const elapsed=(hour-currentKey)+(mins/60);const intensityPerc=Math.max(5,Math.floor((1-(elapsed/blockDuration))*100));let levelKey=(elapsed>=blockDuration*0.7)?"LEVEL_LOW":(elapsed>=blockDuration*0.4)?"LEVEL_MEDIUM":"LEVEL_HIGH";const data=circadianMap[currentKey][isIt?'it':'en'];const advice=getDynamicAdvice(hour,data[3]);const dict=(scientificDict&&scientificDict[isIt?'it':'en'])?scientificDict[isIt?'it':'en']:{};const getDesc=(key)=>{const fallbackMsg=isIt?"Sincronizzazione bio-dati...":"Bio-data syncing...";if(!scientificDict||Object.keys(scientificDict).length===0)return fallbackMsg;if(!key)return dict["default"]||fallbackMsg;const k=key.toString().toUpperCase().trim();return dict[k]||(isIt?(scientificDict.en&&scientificDict.en[k]):(scientificDict.it&&scientificDict.it[k]))||dict["default"]||fallbackMsg};const molName=data[2];const molDesc=getDesc(molName);const advDesc=getDesc(advice);const statDesc=getDesc(data[0]);const sysStateDesc=getDesc(data[1]);const levelInfo=getDesc(levelKey);const labelAdvice=isIt?"CONSIGLIO BIO-LOGICO":"BIO-LOGICAL ADVICE";const labelStatus=isIt?"BIO-STATO":"BIO-STATUS";const labelAnalysis=isIt?"ANALISI DI SISTEMA":"SYSTEM ANALYSIS";const fullMoleculeTooltip=formatTip(molName,molDesc,levelInfo,intensityPerc);const aDesc=formatTip(labelAdvice,advDesc);const sDesc=formatTip(labelStatus,statDesc);const sysDesc=formatTip(labelAnalysis,sysStateDesc);const datePart=`${pad(now.getDate())}/${pad(now.getMonth() + 1)}/${now.getFullYear()}`;const timePart=`${pad(hour)}:${pad(mins)}:${pad(now.getSeconds())}`;clockEl.innerHTML=`
            <div class="hud-inline-row">
                <span data-bio-tip="${fullMoleculeTooltip}">${isIt ? 'MOLECOLA' : 'MOLECULE'}: <b class="bio-data-value">${molName}</b></span>
                <span class="separator">|</span>
                <span data-bio-tip="${aDesc}">${isIt ? 'CONSIGLIO' : 'ADVICE'}: <b class="bio-data-value">${advice}</b></span>
            </div>
            <span class="bio-status-label" data-bio-tip="${sDesc}">${data[0]}</span>
            <span class="bio-clock-time">
                ${datePart} <span class="digits-stable">${timePart}</span>
            </span>
            <span class="bio-system-state" data-bio-tip="${sysDesc}">SYS STATE: ${data[1]}</span>
        `};updateClock();setInterval(updateClock,1000)}
function initWeeklyGreeting(){const weekElement=document.getElementById("week");if(!weekElement)return;const createSpans=(text,start)=>text.split('').map((char,index)=>`<span style='--i:${start + index}'>${char === ' ' ? '&nbsp;' : char}</span>`).join('');const messages={it:['buona domenica!','buon lunedì!','buon martedì!','buon mercoledì!','buon giovedì!','buon venerdì!','buon sabato!'],en:['happy sunday!','happy monday!','happy tuesday!','happy wednesday!','happy thursday!','happy friday!','happy saturday!']};const titles={it:'Biotech Project vi augura ',en:'Biotech Project wishes you '};const greetings={it:['Buonanotte','Buongiorno','Buon pomeriggio','Buonasera'],en:['Good night','Good morning','Good afternoon','Good evening']};const now=new Date(),hour=now.getHours(),today=now.getDay();let gIdx=hour<6?0:hour<14?1:hour<18?2:3;window.requestAnimationFrame(()=>{const daySpans=createSpans(messages[isIt?'it':'en'][today],26);const titleSpans=createSpans(titles[isIt?'it':'en'],1);weekElement.innerHTML=`<div class="greeting-time">${greetings[isIt ? 'it' : 'en'][gIdx]}</div>${titleSpans + daySpans}`})}
function initBiotechTooltips(){let tooltipEl=document.querySelector('.biotech-tooltip')||document.createElement('div');if(!tooltipEl.className){tooltipEl.className='biotech-tooltip';document.body.appendChild(tooltipEl)}
document.addEventListener('mouseover',(e)=>{const target=e.target.closest('[data-bio-tip]');if(target){tooltipEl.innerHTML=target.getAttribute('data-bio-tip');tooltipEl.style.display='block'}});document.addEventListener('mousemove',(e)=>{if(tooltipEl.style.display==='block'){window.requestAnimationFrame(()=>{tooltipEl.style.left=e.clientX+'px';tooltipEl.style.top=(e.clientY-15)+'px';if(e.clientY<100){tooltipEl.style.top=(e.clientY+25)+'px'}})}});document.addEventListener('mouseout',(e)=>{if(e.target.closest('[data-bio-tip]'))tooltipEl.style.display='none'})}
function initDnaScanner(){const dnaScanner=document.getElementById('dna-scanner');if(!dnaScanner)return;dnaScanner.setAttribute('role','button');dnaScanner.setAttribute('tabindex','0');dnaScanner.setAttribute('aria-label',isIt?'Scarica Report Audit Bio-Sincronizzato':'Download Bio-Synchronized Audit Report');dnaScanner.addEventListener('click',(e)=>{e.preventDefault();const currentMol=document.querySelector('.bio-data-value')?.innerText||"DHEA";const intensityElement=document.querySelector('.intensity-value');const currentIntensity=intensityElement?parseInt(intensityElement.innerText):80;const loadingTip=formatTip(isIt?"GENERAZIONE AUDIT":"GENERATING AUDIT",isIt?`Analisi molecolare: <b>${currentMol}</b>`:`Molecular analysis: <b>${currentMol}</b>`,isIt?"Compilazione file PDF in corso...":"Compiling PDF report...",currentIntensity);dnaScanner.setAttribute('data-bio-tip',loadingTip);setTimeout(()=>{executeSecureDownload(currentMol);syncScannerData()},800)});dnaScanner.addEventListener('keydown',(e)=>{if(e.key==='Enter'||e.key===' '){e.preventDefault();dnaScanner.click()}});const executeSecureDownload=async(molecule)=>{const loadJsPDF=()=>{return new Promise((resolve,reject)=>{if(window.jspdf)return resolve(window.jspdf);const script=document.createElement('script');script.src="https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js";script.onload=()=>resolve(window.jspdf);script.onerror=()=>reject(new Error("Errore caricamento libreria PDF"));document.head.appendChild(script)})};try{const{jsPDF}=await loadJsPDF();const doc=new jsPDF({orientation:'p',unit:'mm',format:'a4'});const now=new Date();const lang=isIt?'it':'en';const dict=bioExplanations[lang];const NEON_GREEN=[0,230,118];const TECH_GOLD=[255,204,0];const DARK_ACCENT=[20,30,48];doc.setFillColor(DARK_ACCENT[0],DARK_ACCENT[1],DARK_ACCENT[2]);doc.rect(0,0,210,40,'F');try{doc.addImage("https://gitechnolo.github.io/biotechproject/Biotech-file/images/favicon-biotech.png",'PNG',10,8,24,24)}catch(e){}
doc.setTextColor(167,255,235);doc.setFont("helvetica","bold");doc.setFontSize(20);doc.text("BIOTECH CORE AUDIT",40,18);doc.setFontSize(8);doc.setFont("courier","normal");const season=document.querySelector('.bio-season-label')?.innerText||"STATIONARY";doc.text(`DATE: ${now.toLocaleDateString(lang)} | TIME: ${now.toLocaleTimeString(lang)} | ${season}`,40,25);doc.setDrawColor(NEON_GREEN[0],NEON_GREEN[1],NEON_GREEN[2]);doc.line(0,40,210,40);let yPos=55;doc.setTextColor(DARK_ACCENT[0],DARK_ACCENT[1],DARK_ACCENT[2]);doc.setFont("helvetica","bold");doc.text(isIt?"ANALISI ISTANTANEA":"INSTANT ANALYSIS",15,yPos);yPos+=8;doc.setFillColor(NEON_GREEN[0],NEON_GREEN[1],NEON_GREEN[2],0.05);doc.roundedRect(15,yPos,180,35,2,2,'F');doc.setFontSize(10);doc.text(`${isIt ? 'MOLECOLA' : 'MOLECULE'}:`,20,yPos+10);doc.setTextColor(NEON_GREEN[0],NEON_GREEN[1],NEON_GREEN[2]);doc.setFontSize(16);doc.text(molecule.toUpperCase(),20,yPos+18);const intVal=document.querySelector('.intensity-value')?.innerText||"100%";doc.setFillColor(230,230,230);doc.rect(140,yPos+10,45,4,'F');doc.setFillColor(TECH_GOLD[0],TECH_GOLD[1],TECH_GOLD[2]);doc.rect(140,yPos+10,(45*parseInt(intVal))/100,4,'F');doc.setTextColor(50);doc.setFontSize(8);doc.text(`${isIt ? 'INTENSITÀ' : 'INTENSITY'}: ${intVal}`,140,yPos+18);doc.setTextColor(80);doc.setFont("helvetica","italic");doc.setFontSize(10);const desc=dict[molecule]||dict["default"];doc.text(doc.splitTextToSize(desc,170),20,yPos+28);yPos+=50;doc.setTextColor(DARK_ACCENT[0],DARK_ACCENT[1],DARK_ACCENT[2]);doc.setFont("helvetica","bold");doc.text(isIt?"RIEPILOGO CICLO 24H":"24H CYCLE SUMMARY",15,yPos);const tableY=yPos+5;doc.setFillColor(DARK_ACCENT[0],DARK_ACCENT[1],DARK_ACCENT[2]);doc.rect(15,tableY,180,8,'F');doc.setTextColor(255);doc.text(isIt?"ORA":"TIME",18,tableY+5.5);doc.text(isIt?"MOLECOLA":"MOLECULE",45,tableY+5.5);doc.text(isIt?"STATO DI SISTEMA":"SYSTEM STATE",95,tableY+5.5);let rowY=tableY+8;const cData=[["00:00","ADENOSINA",isIt?"RIGENERAZIONE":"REGEN"],["06:00","CORTISOLO",isIt?"RESET CIRCADIANO":"CIRCADIAN RESET"],["11:00","GLUTAMMATO",isIt?"PICCO COGNITIVO":"COGNITIVE PEAK"],["17:00","MIOCHINE",isIt?"PICCO FISICO":"PHYSICAL PEAK"],["23:00","MELATONINA",isIt?"INIZIO CLEARANCE":"CLEARANCE START"]];cData.forEach((row,i)=>{doc.setFillColor(i%2===0?248:240);doc.rect(15,rowY,180,7,'F');doc.setTextColor(50);doc.text(row[0],18,rowY+5);doc.text(row[1],45,rowY+5);doc.text(row[2],95,rowY+5);rowY+=7});yPos=220;doc.setDrawColor(200);doc.line(15,yPos,195,yPos);const cx=35,cy=250;[[0,150,255],[255,87,34],[TECH_GOLD[0],TECH_GOLD[1],TECH_GOLD[2]]].forEach((c,i)=>{doc.setDrawColor(c[0],c[1],c[2]);doc.setLineWidth(1);doc.ellipse(cx,cy,15-(i*4),15-(i*4))});doc.setTextColor(DARK_ACCENT[0],DARK_ACCENT[1],DARK_ACCENT[2]);doc.text(isIt?"BILANCIAMENTO MACRO":"MACRO BALANCE",60,240);doc.setFontSize(9);doc.text(isIt?"PROT: 40% | CARB: 30% | GRASSI: 30%":"PROT: 40% | CARBS: 30% | FATS: 30%",60,247);const adviceTxt=document.querySelector('.bio-data-value:last-child')?.innerText||"---";doc.setFontSize(12);doc.text(isIt?"CONSIGLIO BIO-LOGICO:":"BIO-LOGICAL ADVICE:",60,260);doc.setTextColor(NEON_GREEN[0],NEON_GREEN[1],NEON_GREEN[2]);doc.text(adviceTxt,60,268);doc.save(`Biotech_Audit_2026_${molecule}.pdf`)}catch(e){console.error(e)}};const syncScannerData=()=>{const molName=document.querySelector('.bio-data-value')?.innerText||"---";const intensityElement=document.querySelector('.intensity-value');const intensity=intensityElement?parseInt(intensityElement.innerText):null;const tipContent=formatTip(isIt?"DNA SCANNER ACTIVE":"DNA SCANNER ACTIVE",isIt?`Sincronia Molecolare: <b>${molName}</b>`:`Molecular Sync: <b>${molName}</b>`,isIt?"Click per scaricare il Report PDF":"Click to download PDF Report",intensity);dnaScanner.setAttribute('data-bio-tip',tipContent)};syncScannerData();setInterval(syncScannerData,1000)}
initSeasonMonitor();initBioClock();initWeeklyGreeting();if('requestIdleCallback' in window){requestIdleCallback(()=>{initBiotechTooltips();console.log("%c⚛️ ENGINE %c Tooltips active in idle phase","color:#00ffcc; background:#002222; padding: 2px 5px; border-radius: 3px; font-weight:bold;","color:#8899af;")})}else{setTimeout(()=>{initBiotechTooltips();console.log("%c⚛️ ENGINE %c Tooltips active via fallback","color:#ffa500; background:#221100; padding: 2px 5px; border-radius: 3px; font-weight:bold;","color:#8899af;")},200)}
setTimeout(initDnaScanner,300)})